function scoreOnDate(person, monthValue) {
  if (person.scoreSegments && person.scoreSegments.length) {
    const target = monthToNumber(monthValue);
    for (let index = 0; index < person.scoreSegments.length; index += 1) {
      const segment = person.scoreSegments[index];
