function rankAmongIndependents(personId, monthValue, people) {
  const cohort = people.filter((person) => !primaryPartyAt(person, monthValue));
  const sorted = cohort.slice().sort((left, right) => {
    const leftScore = Math.abs(scoreOnDate(left, monthValue));
    const rightScore = Math.abs(scoreOnDate(right, monthValue));
    if (leftScore !== rightScore) {
      return leftScore - rightScore;
    }
    return (left.name || "").localeCompare(right.name || "");
  });
  return Math.max(0, sorted.findIndex((person) => person.id === personId));
}

