function lifeChunks(person) {
  const bounds = boundaryMonths(person);
  if (bounds.length < 2) {
    return [{ start: person.birthDate, end: person.deathDate }];
  }
  const chunks = [];
  for (let index = 0; index < bounds.length - 1; index += 1) {
    chunks.push({ start: bounds[index], end: bounds[index + 1] });
  }
  return chunks;
}

