function perpendicularOffsetPx(progress, slot, sign) {
  if (sign === 0 || slot <= 0 || guideLineCount <= 0) {
    return 0;
  }
  const x = clamp(progress, 0, 1) * 1000;
  const half = halfThicknessSvg(x);
  const scaledGap = guideLineCentreGap * (half / 27.3);
  const ySvg = half + slot * scaledGap;
  const scale = window.innerWidth / 1000 * 0.52;
  return sign * ySvg * scale;
}

input.new_string:
function perpendicularOffsetPx(progress, slot, sign) {
  if (sign === 0 || slot <= 0 || guideLineCount <= 0) {
    return 0;
  }
  const x = clamp(progress, 0, 1) * 1000;
  const half = halfThicknessSvg(x);
  const scaledGap = guideLineCentreGap * (half / 27.3);
  const ySvg = half + slot * scaledGap;
  const scale = window.innerWidth / 1000 * 0.52;
  return sign * ySvg * scale;
}

function guideSpacingPxAtProgress(progress) {
  const x = clamp(progress, 0, 1) * 1000;
  const half = halfThicknessSvg(x);
  const scaledGap = guideLineCentreGap * (half / 27.3);
  const scale = window.innerWidth / 1000 * 0.52;
  return scaledGap * scale;
}

function readLineAngleDeg() {
  const raw = getComputedStyle(document.documentElement).getPropertyValue("--line-angle").trim();
  const value = parseFloat(raw);
  return Number.isFinite(value) ? value : 30;
}

/** Viewport (px): point on offset guideline parallel to timeline, at given viewport Y. */
function viewportPointOnOffsetGuide(cx, cy, thetaDeg, signedOffsetPx, vy) {
  const θ = (thetaDeg * Math.PI) / 180;
  const nx = -Math.sin(θ);
  const ny = Math.cos(θ);
  const ux = Math.cos(θ);
  const uy = Math.sin(θ);
  const cn = cx * nx + cy * ny;
  const target = cn + signedOffsetPx;
  if (Math.abs(nx) > 1e-4) {
    const x = (target - vy * ny) / nx;
    return { x, y: vy };
  }
  if (Math.abs(uy) > 1e-4) {
    const t = (vy - cy - signedOffsetPx * ny) / uy;
    return { x: cx + signedOffsetPx * nx + t * ux, y: vy };
  }
  return { x: cx + signedOffsetPx * nx, y: vy };
}

function layoutPersonalityGeometry() {
  if (!actorsLayer || !stage) {
    return;
  }
  const stageRect = stage.getBoundingClientRect();
  const q = readLineAngleDeg();
  const θ = (q * Math.PI) / 180;
  const cx = window.innerWidth / 2;
  const cy = window.innerHeight / 2;
  const w = stage.offsetWidth;
  const h = stage.offsetHeight;
  const midX = w / 2;

  actorsLayer.querySelectorAll(".personality-shape").forEach((svg) => {
    const pB = clamp(Number(svg.dataset.pbirth), 0, 1);
    const pD = clamp(Number(svg.dataset.pdeath), 0, 1);
    const slot = Number(svg.dataset.slot) || 0;
    const sign = Number(svg.dataset.sign) || 0;
    const midMonth = svg.dataset.midMonth || "";
    const mult = midMonth ? interpolateMultiplier(parseMonth(midMonth)) : 0;
    const eps = mult >= 0 ? 1 : -1;
    const zDeg = (q + 180 + eps * 90) / 3;
    const zRad = (zDeg * Math.PI) / 180;
    let zx = Math.cos(zRad);
    let zy = Math.sin(zRad);
    const signDir = sign > 0 ? 1 : sign < 0 ? -1 : 0;
    if (signDir !== 0) {
      const nOutX = signDir * -Math.sin(θ);
      const nOutY = signDir * Math.cos(θ);
      if (zx * nOutX + zy * nOutY < 0) {
        zx = -zx;
        zy = -zy;
      }
    }

    const vyA = stageRect.top + pB * h;
    const vyD = stageRect.top + pD * h;
    const dB = sign === 0 || slot <= 0 ? 0 : perpendicularOffsetPx(pB, slot, signDir);
    const dD = sign === 0 || slot <= 0 ? 0 : perpendicularOffsetPx(pD, slot, signDir);

    const A = viewportPointOnOffsetGuide(cx, cy, q, dB, vyA);
    const D = viewportPointOnOffsetGuide(cx, cy, q, dD, vyD);

    const hBirth = clamp(0.42 * guideSpacingPxAtProgress(pB), 10, 76);
    const hDeath = clamp(0.42 * guideSpacingPxAtProgress(pD), 10, 76);

    const B = { x: A.x + hBirth * zx, y: A.y + hBirth * zy };
    const C = { x: D.x + hDeath * zx, y: D.y + hDeath * zy };

    const Ax = A.x - stageRect.left;
    const Ay = A.y - stageRect.top;
    const Bx = B.x - stageRect.left;
    const By = B.y - stageRect.top;
    const Cx = C.x - stageRect.left;
    const Cy = C.y - stageRect.top;
    const Dx = D.x - stageRect.left;
    const Dy = D.y - stageRect.top;

    const poly = svg.querySelector(".personality-poly");
    const label = svg.querySelector(".personality-label");
    if (poly) {
      poly.setAttribute("points", `${Ax},${Ay} ${Bx},${By} ${Cx},${Cy} ${Dx},${Dy}`);
    }

    if (label) {
      const mx = (Ax + Dx) / 2;
      const my = (Ay + Dy) / 2;
      const adx = Dx - Ax;
      const ady = Dy - Ay;
      const adLen = Math.hypot(adx, ady) || 1;
      const baseAngle = (Math.atan2(ady, adx) * 180) / Math.PI;
      const zAlong = (zx * adx + zy * ady) / adLen;
      const perpAngle = (Math.atan2(zy, zx) * 180) / Math.PI;
      const lift = clamp(0.22 * Math.min(hBirth, hDeath), 3, 14);
      const lx = mx + ((-zy * adx + zx * ady) / adLen) * (lift / Math.max(Math.abs(zAlong), 0.35));
      const ly = my + ((zx * adx + zy * ady) / adLen) * (lift / Math.max(Math.abs(zAlong), 0.35));
      label.setAttribute("transform", `translate(${lx},${ly}) rotate(${baseAngle})`);
      label.setAttribute("text-anchor", "middle");
      label.setAttribute("dominant-baseline", "middle");
      const name = svg.dataset.name || "";
      const maxChars = Math.max(6, Math.floor(adLen / 5.5));
      label.textContent = name.length > maxChars ? `${name.slice(0, maxChars - 1)}…` : name;
      const perpRot = baseAngle + 90 - perpAngle;
      label.setAttribute("transform", `translate(${lx},${ly}) rotate(${perpRot})`);
    }

    svg.setAttribute("viewBox", `0 0 ${w} ${h}`);
  });
}

